<script setup lang="ts">
import { UiButton,UiCard,UiField,UiInput,UiTextarea } from "@moecraft/ui";
import type { ProductFieldFeedback,ProductReviewDetail } from "@moecraft/shared";
defineProps<{product:ProductReviewDetail;reason:string;fieldFeedback:ProductFieldFeedback[];busy:boolean;canReview:boolean}>();
const emit=defineEmits<{close:[];approve:[];reject:[];"update:reason":[value:string];addFeedback:[];removeFeedback:[index:number]}>();
const fields=["titleZhCn","descriptionZhCn","categoryId","brandId","franchiseId","characterId","material","scale","copyrightNotice","skus","media.cover"];
</script>
<template><div class="mask" @mousedown.self="emit('close')"><aside class="drawer"><header><div><small>PRODUCT REVIEW</small><h2>{{product.titleZhCn}}</h2><p>{{product.storeName}} · {{product.status}}</p></div><UiButton variant="ghost" aria-label="关闭" @click="emit('close')">×</UiButton></header><div class="scroll"><section class="summary"><UiCard title="商品资料"><dl><div><dt>中文标题</dt><dd>{{product.titleZhCn}}</dd></div><div><dt>英文标题</dt><dd>{{product.titleEnUs||'—'}}</dd></div><div><dt>类目</dt><dd>{{product.categoryId||'—'}}</dd></div><div><dt>材质 / 比例</dt><dd>{{product.material||'—'}} / {{product.scale||'—'}}</dd></div><div class="wide"><dt>中文描述</dt><dd>{{product.descriptionZhCn||'—'}}</dd></div><div class="wide"><dt>版权信息</dt><dd>{{product.copyrightNotice||'—'}}</dd></div></dl></UiCard><UiCard :title="`SKU（${product.skus.length}）`"><article v-for="sku in product.skus" :key="sku.id"><b>{{sku.nameZhCn}}</b><span>{{sku.code}} · ¥{{(sku.priceAmount/100).toFixed(2)}} · 库存 {{sku.initialStock}}</span></article></UiCard><UiCard :title="`媒体（${product.media.length}）`"><article v-for="media in product.media" :key="media.id"><b>{{media.kind}}{{media.isCover?' · 封面':''}}</b><span>{{media.fileId}} · {{media.altZhCn||'无 Alt'}}</span></article></UiCard></section><section v-if="product.reviewEvents.length" class="timeline"><h3>审核时间线</h3><article v-for="event in product.reviewEvents" :key="event.id"><i/><div><b>{{event.fromStatus}} → {{event.toStatus}}</b><time>{{new Date(event.createdAt).toLocaleString()}}</time><p v-if="event.reason">{{event.reason}}</p><ul v-if="event.fieldFeedback.length"><li v-for="feedback in event.fieldFeedback" :key="`${feedback.field}-${feedback.message}`">{{feedback.field}}：{{feedback.message}}</li></ul></div></article></section><section v-if="canReview&&product.status==='PENDING_REVIEW'" class="decision"><h3>审核意见</h3><UiField label="总体意见" hint="驳回时总体意见或字段意见至少填写一项"><UiTextarea :model-value="reason" rows="3" placeholder="说明审核依据" @update:model-value="emit('update:reason',$event)"/></UiField><div class="feedback-head"><b>字段级意见</b><UiButton size="sm" variant="secondary" @click="emit('addFeedback')">＋ 添加意见</UiButton></div><div v-for="(item,index) in fieldFeedback" :key="index" class="feedback"><select v-model="item.field"><option value="">选择字段</option><option v-for="field in fields" :key="field" :value="field">{{field}}</option></select><UiInput v-model="item.message" placeholder="具体修改建议"/><UiButton size="sm" variant="ghost" @click="emit('removeFeedback',index)">移除</UiButton></div></section></div><footer v-if="canReview&&product.status==='PENDING_REVIEW'"><UiButton variant="danger" :loading="busy" @click="emit('reject')">驳回并退回商家</UiButton><UiButton :loading="busy" @click="emit('approve')">审核通过</UiButton></footer></aside></div></template>
<style scoped lang="less">.mask{position:fixed;z-index:120;inset:0;display:flex;justify-content:flex-end;background:#1714238c}.drawer{display:flex;width:min(780px,96vw);height:100%;flex-direction:column;background:var(--surface);color:var(--text);box-shadow:-30px 0 80px #1113}.drawer>header{display:flex;justify-content:space-between;padding:23px 28px;border-bottom:1px solid var(--border)}header small{color:var(--accent);font-size:9px;letter-spacing:.16em}header h2{margin:7px 0 4px}header p{margin:0;color:var(--text-muted);font-size:11px}.scroll{flex:1;overflow:auto;padding:22px 28px}.summary{display:grid;gap:14px}dl{display:grid;grid-template-columns:1fr 1fr;gap:14px;margin:0}dl div{display:grid;gap:4px}.wide{grid-column:1/-1}dt{color:var(--text-muted);font-size:10px}dd{margin:0;line-height:1.6}article{display:flex;justify-content:space-between;gap:12px;padding:10px 0;border-bottom:1px solid var(--border)}article span{color:var(--text-muted);font-size:10px}.timeline,.decision{padding-top:24px}.timeline article{justify-content:flex-start}.timeline i{width:9px;height:9px;margin-top:5px;border-radius:50%;background:var(--accent)}.timeline article div{display:grid;flex:1}.timeline time{color:var(--text-muted);font-size:9px}.timeline p{margin:6px 0}.feedback-head{display:flex;align-items:center;justify-content:space-between;margin:16px 0 8px}.feedback{display:grid;grid-template-columns:180px 1fr auto;gap:8px;margin-top:8px}.feedback select{border:1px solid var(--border);border-radius:8px;background:var(--surface-raised);color:var(--text)}.drawer>footer{display:flex;justify-content:flex-end;gap:10px;padding:17px 28px;border-top:1px solid var(--border)}@media(max-width:600px){dl{grid-template-columns:1fr}.wide{grid-column:auto}.feedback{grid-template-columns:1fr}}</style>
